INSERT INTO departments VALUES(35,'Diabetics, Hormone & Nutrition','diabetics,-hormone-&-nutrition','‘Balancing hormones, balancing life.’',NULL,replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Diabetic, Hormone &amp; Nutrition</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">The department diagnoses and treats hormone-related disorders, including diabetes, thyroid, and metabolic diseases, as well as related nutritional issues.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Diabetes management programs</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Thyroid ultrasound &amp; FNAC</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Hormone replacement therapy</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Osteoporosis screening</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Obesity management</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Type 1 &amp; 2 diabetes</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Thyroid disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Adrenal disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Pituitary disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Osteoporosis</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="diabeticFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="df1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#diabeticCollapse1" aria-expanded="true" aria-controls="diabeticCollapse1"> Do you treat childhood diabetes? </button></h6>\r\n</div>\r\n<div id="diabeticCollapse1" class="collapse" aria-labelledby="df1" data-parent="#diabeticFaqAccordion">\r\n<div class="card-body text-dark">Yes, with pediatric endocrine support.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="df2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#diabeticCollapse2" aria-expanded="false" aria-controls="diabeticCollapse2"> Is insulin therapy taught here? </button></h6>\r\n</div>\r\n<div id="diabeticCollapse2" class="collapse" aria-labelledby="df2" data-parent="#diabeticFaqAccordion">\r\n<div class="card-body text-dark">Yes, with hands-on training.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="df3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#diabeticCollapse3" aria-expanded="false" aria-controls="diabeticCollapse3"> Do you have a weight loss clinic? </button></h6>\r\n</div>\r\n<div id="diabeticCollapse3" class="collapse" aria-labelledby="df3" data-parent="#diabeticFaqAccordion">\r\n<div class="card-body text-dark">Yes, as part of obesity management.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap JS dependencies -->','\r',char(13)),'\n',char(10)),26,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 09:57:15');
INSERT INTO departments VALUES(36,'Surgical Oncology','surgical-oncology','‘Precision surgery in the fight against cancer.’',NULL,replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f4f7f9, #e8f1f0, #dfe6f0); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Surgical Oncology</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">The Surgical Oncology Department focuses on surgical management of cancers, combining precision surgery with multidisciplinary care. We work closely with medical and radiation oncology teams for optimal outcomes.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Tumor excision and organ-preserving surgeries</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Breast cancer surgery (lumpectomy, mastectomy)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Gastrointestinal cancer surgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Head and neck cancer surgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Lymph node dissections</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Breast, colon, liver, and stomach cancers</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Head and neck malignancies</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Skin cancers (melanoma, basal cell carcinoma)</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="surgOncoFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#surgCollapse1" aria-expanded="true" aria-controls="surgCollapse1"> Is surgery always needed for cancer treatment? </button></h6>\r\n</div>\r\n<div id="surgCollapse1" class="collapse" aria-labelledby="faq1" data-parent="#surgOncoFaqAccordion">\r\n<div class="card-body text-dark">Not always; surgery depends on cancer type, stage, and overall treatment plan with oncology team.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#surgCollapse2" aria-expanded="false" aria-controls="surgCollapse2"> How soon can surgery be done after diagnosis? </button></h6>\r\n</div>\r\n<div id="surgCollapse2" class="collapse" aria-labelledby="faq2" data-parent="#surgOncoFaqAccordion">\r\n<div class="card-body text-dark">Surgery timing depends on the treatment plan and patient readiness, often coordinated with oncology.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#surgCollapse3" aria-expanded="false" aria-controls="surgCollapse3"> What&rsquo;s the recovery period for major cancer surgery? </button></h6>\r\n</div>\r\n<div id="surgCollapse3" class="collapse" aria-labelledby="faq3" data-parent="#surgOncoFaqAccordion">\r\n<div class="card-body text-dark">Recovery varies by procedure; typically 4-8 weeks for major surgeries, with ongoing follow-up.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap 4.5 JS dependencies -->','\r',char(13)),'\n',char(10)),16,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 09:56:58');
INSERT INTO departments VALUES(37,'Pediatric Hematology and Oncology','pediatric-hematology-and-oncology','‘Fighting illness with courage, care, and compassion — for every child.’',NULL,replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Pediatric Hematology &amp; Oncology</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">Our Pediatric Hematology &amp; Oncology Department offers specialized care for pediatric blood disorders and cancers, including leukemia management, hemophilia treatment, and transfusion-related therapies in children.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Leukemia &amp; lymphoma treatment in children</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Anemia &amp; bleeding disorder management</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Child-friendly chemotherapy support</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Family-centered psychosocial counseling</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Leukemia, lymphomas, other pediatric malignancies</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Anemias, bleeding disorders, hemoglobinopathies</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="pedhemaFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="phf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#phemaCollapse1" aria-expanded="true" aria-controls="phemaCollapse1"> How to initiate treatment for pediatric cancers? </button></h6>\r\n</div>\r\n<div id="phemaCollapse1" class="collapse" aria-labelledby="phf1" data-parent="#pedhemaFaqAccordion">\r\n<div class="card-body text-dark">Initial consultation with pediatric oncologists is recommended, along with diagnostic tests and treatment planning.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="phf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#phemaCollapse2" aria-expanded="false" aria-controls="phemaCollapse2"> Are specialized transfusion services offered? </button></h6>\r\n</div>\r\n<div id="phemaCollapse2" class="collapse" aria-labelledby="phf2" data-parent="#pedhemaFaqAccordion">\r\n<div class="card-body text-dark">Yes, transfusions are child-friendly and managed under strict safety protocols.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="phf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#phemaCollapse3" aria-expanded="false" aria-controls="phemaCollapse3"> What support is available for families during oncology care? </button></h6>\r\n</div>\r\n<div id="phemaCollapse3" class="collapse" aria-labelledby="phf3" data-parent="#pedhemaFaqAccordion">\r\n<div class="card-body text-dark">Counseling, psychosocial support, and educational guidance are provided for families throughout the treatment journey.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap 4.5 JS dependencies -->','\r',char(13)),'\n',char(10)),23,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 09:55:56');
INSERT INTO departments VALUES(38,'Liver & Gastroenterology','liver-&-gastroenterology','Expert hands for the most delicate organs.',NULL,replace(replace('<div class="container">\r\n<div class="row"><!-- Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100 w-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e0f2f1); color: #111; backdrop-filter: blur(8px);">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Liver &amp; Gastroenterology</h2>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;"><br><br>Our Liver &amp; Gastroenterology Department specializes in the diagnosis, treatment, and management of liver, stomach, and intestinal disorders. We offer advanced endoscopic and minimally invasive procedures, supported by expert gastroenterologists and hepatologists.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Key Services -->\r\n<div class="col-md-6 col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100 w-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px);">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><strong><span class="text-success mr-2">✓ </span></strong>Diagnostic and therapeutic endoscopy</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Liver function assessment and treatment</li>\r\n<li class="mb-2"><strong><span class="text-success mr-2">✓ </span></strong>Hepatitis screening and management</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Treatment of acid reflux, ulcers, and digestive disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Nutritional counseling for digestive health</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Common Conditions -->\r\n<div class="col-md-6 col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100 w-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px);">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Hepatitis A, B, C</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Cirrhosis and fatty liver</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Peptic ulcer disease</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Irritable bowel syndrome (IBS)</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Gastroesophageal reflux disease (GERD)</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQs -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100 w-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px);">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="gastroFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="gfq1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#gastroCollapse1" aria-expanded="true" aria-controls="gastroCollapse1"> What&rsquo;s the difference between hepatology and gastroenterology? </button></h6>\r\n</div>\r\n<div id="gastroCollapse1" class="collapse" aria-labelledby="gfq1" data-parent="#gastroFaqAccordion">\r\n<div class="card-body text-dark">Hepatology focuses on liver-related conditions, while gastroenterology covers the digestive tract, including the liver, stomach, intestines, and pancreas.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="gfq2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#gastroCollapse2" aria-expanded="false" aria-controls="gastroCollapse2"> Are endoscopic procedures painful? </button></h6>\r\n</div>\r\n<div id="gastroCollapse2" class="collapse" aria-labelledby="gfq2" data-parent="#gastroFaqAccordion">\r\n<div class="card-body text-dark">Most endoscopic procedures are not painful, as they are done under sedation or local anesthesia for patient comfort.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="gfq3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#gastroCollapse3" aria-expanded="false" aria-controls="gastroCollapse3"> Can fatty liver be reversed? </button></h6>\r\n</div>\r\n<div id="gastroCollapse3" class="collapse" aria-labelledby="gfq3" data-parent="#gastroFaqAccordion">\r\n<div class="card-body text-dark">Yes, lifestyle changes, weight loss, and proper medical management can often reverse fatty liver in its early stages.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>','\r',char(13)),'\n',char(10)),20,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 09:53:35');
INSERT INTO departments VALUES(39,'Psychology','psychology','NULL',NULL,replace(replace('<p class="pbmit-firstletter">\r\n        Main Hospitals or larger hospital systems may provide their own ambulance service as a service to the community, or where ambulance care is unreliable or chargeable. Many hospital-based EMS departments operate solely with their hospital\r\n     </p>\r\n     <p>The physicians will attempt to treat casualties at the scene and will only transport them to hospital if it is deemed necessary. If patients are transported to hospital, they are more likely to go straight to a ward rather than to <u>an emergency department</u> . Countries that use this model include Austria, France, Belgium, Luxembourg, Italy, Spain, Brazil and Chile.</p>\r\n     <div class="row">\r\n        <div class="col-md-6">\r\n           <ul class="list-group list-group-borderless">\r\n              <li class="list-group-item">\r\n                 <span class="pbmit-icon-list-icon">\r\n                    <i aria-hidden="true" class="ti-check"></i>\r\n                 </span>\r\n                 <span class="pbmit-icon-list-text">That extremely painful or again is there anyone.</span>\r\n              </li>\r\n              <li class="list-group-item">\r\n                 <span class="pbmit-icon-list-icon">\r\n                    <i aria-hidden="true" class="ti-check"></i>\r\n                 </span>\r\n                 <span class="pbmit-icon-list-text">Indignation and dislike men who are so beguiled</span>\r\n              </li>\r\n              <li class="list-group-item">\r\n                 <span class="pbmit-icon-list-icon">\r\n                    <i aria-hidden="true" class="ti-check"></i>\r\n                 </span>\r\n                 <span class="pbmit-icon-list-text">Desires these cases are perfectly simple easy distinguish.</span>\r\n              </li>\r\n              <li class="list-group-item">\r\n                 <span class="pbmit-icon-list-icon">\r\n                    <i aria-hidden="true" class="ti-check"></i>\r\n                 </span>\r\n                 <span class="pbmit-icon-list-text">That extremely painful or again that is there anyone.</span>\r\n              </li>\r\n           </ul>\r\n        </div>\r\n        <div class="col-md-6">\r\n           <ul class="list-group list-group-borderless">\r\n              <li class="list-group-item">\r\n                 <span class="pbmit-icon-list-icon">\r\n                    <i aria-hidden="true" class="ti-check"></i>\r\n                 </span>\r\n                 <span class="pbmit-icon-list-text">Starchy foods are a key food group in healthy eating</span>\r\n              </li>\r\n              <li class="list-group-item">\r\n                 <span class="pbmit-icon-list-icon">\r\n                    <i aria-hidden="true" class="ti-check"></i>\r\n                 </span>\r\n                 <span class="pbmit-icon-list-text">People are sleeping much less than they did in the past</span>\r\n              </li>\r\n              <li class="list-group-item">\r\n                 <span class="pbmit-icon-list-icon">\r\n                    <i aria-hidden="true" class="ti-check"></i>\r\n                 </span>\r\n                 <span class="pbmit-icon-list-text">Don’t smoke or use drugs, and only drink in moderation</span>\r\n              </li>\r\n              <li class="list-group-item">\r\n                 <span class="pbmit-icon-list-icon">\r\n                    <i aria-hidden="true" class="ti-check"></i>\r\n                 </span>\r\n                 <span class="pbmit-icon-list-text">Your body is full of trillions of bacteria, viruses and fungi</span>\r\n              </li>\r\n           </ul>\r\n        </div>\r\n     </div>','\r',char(13)),'\n',char(10)),25,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 09:51:59');
