INSERT INTO doctors VALUES(1,1,'Professor Dr. Ahmedul Kabir','professor-dr.-ahamedul-kabir','Medicine Specialist','MBBS,  FCPS, FACP, FRCP,','Professor','Former ADG (Admin), DGHS',replace('<p class="pbmit-firstletter">Here&rsquo;s a situation that comes up for many people: you move in later life. For most older adults, establishing a good working relationship with a new doctor is a challenge. If nothing else, it can take some time to feel that each party knows and understands the other. And they leave it to the new doctors to request health information from the previous doctors, which often arrives well after that first new patient visit. In this post, I&rsquo;ll share my list of the most useful health information</p>\n<p>A profile of a doctor is an effective personal marketing that doctors utilise to showcase their specialisation, qualifications and expertise. Creating a profile is beneficial for doctors as it ensures that others around them know their background</p>','\n',char(10)),'OB - 201',1500,NULL,'1847331011','NULL','A00001',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-27 04:42:58');
