INSERT INTO doctors VALUES(18,8,'Professor Dr. Md. Jahangir Alam','asso.-prof.-dr.-md.-jahangir-alam','Hepatology Head of Department (Hepatology)','MBBS, MD (Hepatology)','Asso. Prof. And Department Head Of Hepatology','Shaheed Suhrawardy Medical College and Hospital',replace('<p class="pbmit-firstletter">Here&rsquo;s a situation that comes up for many people: you move in later life. For most older adults, establishing a good working relationship with a new doctor is a challenge. If nothing else, it can take some time to feel that each party knows and understands the other. And they leave it to the new doctors to request health information from the previous doctors, which often arrives well after that first new patient visit. In this post, I&rsquo;ll share my list of the most useful health information</p>\n<p>A profile of a doctor is an effective personal marketing that doctors utilise to showcase their specialisation, qualifications and expertise. Creating a profile is beneficial for doctors as it ensures that others around them know their background</p>','\n',char(10)),'NB-1601',1000,NULL,'1409961019','NULL','J00001',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-27 04:42:58');
INSERT INTO doctors VALUES(19,9,'Prof. Dr. Mohammad Jamal Abu Nasser','prof.-dr.-mohammad-jamal-abu-nasser','General, LASER Proctology & Advanced Laparoscopic Surgeon','MBBS, FCPS (Surgery), FMAS (India)','General, Laparoscopic, Breast, Hernia, Colo-rectal and LASER Proctology','Enam Medical College & Hospital',replace('<p dir="ltr">Mohammad Dr. Jamal Abu Nasser completed his Graduation (MBBS) from Dinajpur Medical College in the year 2000. He has extensively trained himself for Post graduation in General Surgery under Renowned professors of Dhaka Medical College Hospital. From 2006 to 2012, he was posted as Registrar, Resident Surgeon (RS) of General Surgery in different well reputed institutions including Shahabuddin Medical College, International Medical College and Northern International Medical College.</p>\n<p dir="ltr"><br>He achieved his fellowship (FCPS) in General Surgery from Bangladesh College of Physician and Surgeon (BCPS) in the year 2013. After completion of his fellowship, he worked as Assistant Professor and acting Head of the department of Surgery in Monno Medical College from 2013 to 2016. Thereafter he was promoted &amp; worked as Associate Professor and head of the department of Surgery in Ashian Medical College from 2016 to 2017. He also worked as Associate Professor in the department of Surgery of Shahabuddin Medical College from 2017 to 2020. Then he joined as Associate professor in the department of surgery of Ashiyan Medical College in 2020 and was promoted there as Professor (C.C) on 11.02.202.</p>\n<p dir="ltr">Now he is working as Professor of surgery at Enam Medical Collage &amp; hospital which is one of the top class Medical College in Bangladesh</p>\n<p dir="ltr"><br>He also worked as Vice Principal (In-charge) in Ashiyan Medical College from 2020 to 2022. During the course of a successful career spanning over 25 years, he has attended many scientific seminars, conferences in Bangladesh and abroad to update his knowledge in the field of General &amp; Laparoscopic Surgery to provide the latest treatment to his patients. To enrich his surgical hand, he participated in many workshops in laparoscopic surgery in Bangladesh including Robotic surgery in India.</p>\n<p dir="ltr"><br>He earned Fellowship in Minimal Access Surgery (Laparoscopic surgery) FMAS, of Association of Minimal Access Surgeons of India (AMASI) in 2017. He has got training in LASER Proctology (treatment of haemorrhoid, anal fissure, pilonidal sinus and fistula in ano through LASER from India. His mentor was world famous LASER Proctology surgeon Prof. Dr. Kalyan kour at AMRI hospital, Kolkata, India in 2019.<br>He is an excellent general, laparoscopic and LASER Proctology surgeon and has performed every type of surgical procedure meticulously and confidently. Dr. Nasser is proficient in performing Gastrointestinal surgeries including Colorectal surgeries, Hepatobiliary surgeries, Hernia surgeries by both open and laparoscopic methods. Moreover he has got special expertise in performing Breast surgeries and all kinds of Ano-rectal surgeries including Longo operation (Stapled Haemorrhoidectomy) and STARR (Stapled Transanal Rectal Resection).</p>\n<p dir="ltr"><br>He is a LASER Proctology Surgeon who performed Anal Fissure, Hemorrhoid, Fistula in Ano and Pilonidal sinus operation with LASER. He is an excellent teacher for undergraduate students and has experience of teaching for 19 long years. He has been playing an important role in some academic activities of Bangladesh College of Physicians and Surgeons (BCPS) for postgraduate medical students. Dr. Nasser is a life member of SOSB (Society of Surgeon of Bangladesh) and SELSB (Society of Endo-Laparoscopic Surgeon of Bangladesh). He has contributed to no less than 16 scientific publications in journals of various distinguished Medical Colleges of Bangladesh.</p>','\n',char(10)),'NB-1603',1000,NULL,'1847331028','NULL','NULL',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-27 04:42:58');
