INSERT INTO doctors VALUES(35,17,'Assistant Prof. Dr. Md. Asaduzzaman','assistant-prof.-dr.-md.-asaduzzaman','Orthopedics','MBBS (DU), CCD (BIRDEM), D-Ortho (BSMMU)','Associate Professor and Head of Orthopedic Department','Bikrompur Bhuyan Medical College',replace('<p style="text-align: justify; background: white; margin: 0in 0in 18.75pt 0in;"><span style="font-size: 13.5pt; font-family: ''Arial'',''sans-serif''; color: #313131;">Dr. Md. Ashaduzzaman obtained his MBBS from Holy Family Red Crescent Medical College under Dhaka University. He also obtained D-ortho post graduation degree from BSMMU in 2019.</span></p>\n<p style="text-align: justify; background: white; box-sizing: border-box; font-variant-ligatures: normal; font-variant-caps: normal; orphans: 2; widows: 2; -webkit-text-stroke-width: 0px; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; word-spacing: 0px; margin: 0in 0in 18.75pt 0in;"><span style="font-size: 13.5pt; font-family: ''Arial'',''sans-serif''; color: #313131;">He has completed his post graduation training from DMCH, DJMCH &amp; BSMMU. Also done short courses like CCD from BIRDEM hospital and AO Basic Trauma course from AO foundation.</span></p>\n<p style="text-align: justify; background: white; box-sizing: border-box; font-variant-ligatures: normal; font-variant-caps: normal; orphans: 2; widows: 2; -webkit-text-stroke-width: 0px; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; word-spacing: 0px; margin: 0in 0in 18.75pt 0in;"><span style="font-size: 13.5pt; font-family: ''Arial'',''sans-serif''; color: #313131;">He has been in Ad-din Women&rsquo;s Medical College for 2 years from December, 2019 as Assistant Professor, Orthopaedics department.&nbsp;</span></p>\n<p style="text-align: justify; background: white; box-sizing: border-box; font-variant-ligatures: normal; font-variant-caps: normal; orphans: 2; widows: 2; -webkit-text-stroke-width: 0px; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; word-spacing: 0px; margin: 0in 0in 18.75pt 0in;"><span style="font-size: 13.5pt; font-family: ''Arial'',''sans-serif''; color: #313131;">He has participated in the &lsquo;<strong style="box-sizing: border-box;"><span style="font-family: ''Arial'',''sans-serif'';">MASTER COURSE ON TRAUMA &amp; SPINE SURGERY</span></strong>&lsquo; held on June 2022 in Chennai.</span></p>\n<p style="text-align: justify; background: white; box-sizing: border-box; font-variant-ligatures: normal; font-variant-caps: normal; orphans: 2; widows: 2; -webkit-text-stroke-width: 0px; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; word-spacing: 0px; margin: 0in 0in 18.75pt 0in;"><span style="font-size: 13.5pt; font-family: ''Arial'',''sans-serif''; color: #313131;">Alongside his professional responsibilities Dr. Md. Asaduzzaman is closely involved with social activities. He is a Member of Bangladesh Orthopaedic Society.</span></p>\n<p style="text-align: justify; background: white; box-sizing: border-box; font-variant-ligatures: normal; font-variant-caps: normal; orphans: 2; widows: 2; -webkit-text-stroke-width: 0px; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; word-spacing: 0px; margin: 0in 0in 18.75pt 0in;"><span style="font-size: 13.5pt; font-family: ''Arial'',''sans-serif''; color: #313131;">He was born in Manikganj and studied at Dhaka Residential Model College. He is married and blessed with two daughters.</span></p>','\n',char(10)),'-',1000,NULL,'NULL','NULL','A00061',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-27 04:42:58');
