INSERT INTO doctors VALUES(39,18,'Prof. Dr. Saeedur Rahman','prof.-dr.-saeedur-rahman','Pediatric specialist','MBBS (DMC), FCPS (Pediatrics)','Senior Consultant','AMZ Hospital Ltd. (Pediatrician)',replace('<p>As a Specialist Physician in Pediatrics and Neonatology he has gained a diversified experience and cross-functional expertise by working and living in 3 different countries: Bangladesh, Iran &amp; Saudi Arabia. He wants to serve the pediatric age group of patients sincerely and wholeheartedly with devotion with his knowledge and skills that he acquired in the last 39 years in the field of pediatrics, both at home and abroad.</p>\n<p>Prof. Dr. Saeedur Rahman completed his graduation (MBBS) from Dhaka Medical College in the year 1980.</p>\n<p>Thereafter he has served as Health Cadre, Bangladesh Civil Service from year 1981 till year 1990, he was a lecturer of Pathology at Sylhet Medical College and Hospital for a year.</p>\n<p>He achieved his FCPS from Bangladesh College of Physicians &amp; Surgeons in the year 1989.</p>\n<p>From year 1990 till year 1991 he was a Senior Registrar, Pediatrics at Dhaka Shishu (Children) Hospital.</p>\n<p>In the year 1991 he joined Ministry of Health, Islamic Republic of Iran as a Pediatric Specialist and served in three different district hospitals till year 1993.&nbsp;</p>\n<p>He has also worked as a Professor, Pediatric Consultant &amp; Head of the Department of Pediatrics at Jahurul Islam Medical College &amp; Hospital for 13 long years from 1994 till 2007.</p>\n<p>Then he joined United Hospital Ltd. as a Pediatric Consultant and worked there from year 2007 till year 2008.</p>\n<p>Then he joined Al-Qunfudah General Hospital as a Pediatric Specialist in Kingdom of Saudi Arabia and worked from year 2008 till year 2018.</p>\n<p>Upon his return from Kingdom of Saudi Arabia he joined as a Senior Consultant, Pediatrics at BRB Hospital Limited and served there from year 2018 till year 2021.</p>\n<p>Currently he has joined AMZ Hospital Limited as Senior Consultant, Pediatric from year 2021 and ever since he has been treating patients delicately.</p>\n<p>&nbsp;</p>','\n',char(10)),'NB-1502',1000,NULL,'1847331012','NULL','S00113',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-27 04:42:58');
INSERT INTO doctors VALUES(40,18,'Professor Dr. Delowar Hossain Mollah','asso.-prof.-dr.-delowar-hossain-mollah','Pediatric specialist','MBBS, FCPS (Pediatrics)','Professor','Uttara Women''s Medical College, Bangladesh',replace('<p class="pbmit-firstletter">Here&rsquo;s a situation that comes up for many people: you move in later life. For most older adults, establishing a good working relationship with a new doctor is a challenge. If nothing else, it can take some time to feel that each party knows and understands the other. And they leave it to the new doctors to request health information from the previous doctors, which often arrives well after that first new patient visit. In this post, I&rsquo;ll share my list of the most useful health information</p>\n<p>A profile of a doctor is an effective personal marketing that doctors utilise to showcase their specialisation, qualifications and expertise. Creating a profile is beneficial for doctors as it ensures that others around them know their background</p>','\n',char(10)),'NB-1602',1000,NULL,'1409961022','NULL','D00001',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-27 04:42:58');
INSERT INTO doctors VALUES(41,18,'Asst. Prof. Dr. Md. Abdul Maleque Molla','asst.-prof.-dr.-md.-abdul-maleque-molla','Pediatric Specialist','MRCP (UK), MRCPCH (UK), FRCP (ED), FRCPCH, DCH','Asst. Professor','Imam Mohamman Ibn Saoud Islamic University',replace('<p style="text-align: justify; background: white; margin: 0in 0in 18.75pt 0in;"><strong><span style="font-family: ''Arial'',''sans-serif''; color: #313131;">Dr Mohammed Abdul Maleque Molla</span></strong><span style="font-family: ''Arial'',''sans-serif''; color: #313131;">&nbsp;was graduated from Rajshahi Medical College in 1975. He started his carrier in Paediatrics in 1985 after completion of Diploma in Paeditrics and Child health (DCH). He joined department of Paediatrics in King Khaled hospital, Al Kharj in 1985.&nbsp; It was a newly build 200 bed general hospital where he organized a Neonatal ICU. In 1989 he joined Al Yamamah Maternity and Children Hospital, a 300 bedded hospital with 100 bedded Neonatology unit and 40 bedded General Paediatrics department including 7 bedded Pediatric Intensive care unit. In 1996 he moves to United Kingdom and joined,</span><span style="box-sizing: border-box;">&nbsp;Royal Hospital for Sick Children, York Hill, Glasgow.</span></p>\n<p style="text-align: justify; background: white; box-sizing: border-box; font-variant-ligatures: normal; font-variant-caps: normal; orphans: 2; widows: 2; -webkit-text-stroke-width: 0px; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; word-spacing: 0px; margin: 0in 0in 18.75pt 0in;"><span style="box-sizing: border-box;"><span style="font-family: ''Arial'',''sans-serif''; color: #313131;">In 1997 he passed the MRCP(UK) and return back to Riyadh and joined Al Yamamamh Hospital. He was posted as Consultant Neonatologist and worked until 2001 when he was posted in&nbsp; Paediatric Intensive care Unit as Consultant Paediatic Intensivist until December 2021. Besides his job he had special interest in Pediatric Pulmonology. He was organizing Pediatric Pulmonology and Asthma Clinics in Yamamah Hospital since 1997 until 2019. He also took training in Bronchoscopy from King Faisal Hospital, Riyadh, Saudi Arabia</span></span></p>\n<p style="text-align: justify; background: white; box-sizing: border-box; font-variant-ligatures: normal; font-variant-caps: normal; orphans: 2; widows: 2; -webkit-text-stroke-width: 0px; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; word-spacing: 0px; margin: 0in 0in 18.75pt 0in;"><span style="box-sizing: border-box;"><span style="font-family: ''Arial'',''sans-serif''; color: #313131;">He was trained in paediatrics and neonatal Intensive care medicine in various hospital specially in UK and Saudi Arabia. Al Yamamah Hospital is one of the largest Maternity and Children Hospital in the Kingdom of Saudi Arabia. Intensive care units are equipped with most advance and modern equipment&rsquo;s. It is a referral center and was accepting patients from all over the Kingdom.</span></span></p>\n<p style="text-align: justify; background: white; box-sizing: border-box; font-variant-ligatures: normal; font-variant-caps: normal; orphans: 2; widows: 2; -webkit-text-stroke-width: 0px; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; word-spacing: 0px; margin: 0in 0in 18.75pt 0in;"><span style="box-sizing: border-box;"><span style="font-family: ''Arial'',''sans-serif''; color: #313131;">Al Yamamah hospital is one of the educational centers in Kingdom of Saudi Arabia and running Saudi board training programs in Paediatrics, Obs and Gynae and Dentistry. There is Fellowship program in Neonatology, jointly with King Fahad Medical City, Riyadh. For Undergraduate teaching program, three Universities (Imam Mohammad Ibn Saud Islamic University, Al Marefa University, Dar Al Uloom University) in Riyadh, are affiliated with Al Yamamah Hospital for theritical and practical training for their students.</span></span></p>\n<p style="text-align: justify; background: white; box-sizing: border-box; font-variant-ligatures: normal; font-variant-caps: normal; orphans: 2; widows: 2; -webkit-text-stroke-width: 0px; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; word-spacing: 0px; margin: 0in 0in 18.75pt 0in;"><span style="box-sizing: border-box;"><span style="font-family: ''Arial'',''sans-serif''; color: #313131;">Dr. Molla was teacher for post graduate Saudi Board students in Al Yamamah Hospital and teaching the undergraduate student from three universities. He was given post of assistant Professor of Pediatrics from Imam Mohammad Ibn Saud Islamic University and Al Marefa University, Riyadh, Saudi Arabia.&nbsp; He was examiner in Saudi Commission For Health Specialties for Saudi Board and Arab Board programs.&nbsp; He was organizing postgraduate courses for MRCPCH and Saudi Paediatrics board programs&nbsp; was organizer of many seminars and Paediatrics &amp; Neonatal club meetings in Yamamah hospital. He published many scientific papers in reputed medical Journals.</span></span></p>\n<p class="MsoNormal" style="text-align: justify;"><span style="font-size: 10.0pt; line-height: 5%; font-family: ''Arial'',''sans-serif'';">&nbsp;</span></p>','\n',char(10)),'NB-1602',1000,NULL,'1409961043','NULL','M00098',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-27 04:42:58');
INSERT INTO doctors VALUES(42,18,'ASST. PROF. Dr. Jannatul Mawa','asst.-prof.-dr.-jannatul-mawa','Pediatric Specialist','MBBS, DCH (BSMMU)','Ex-Asst. Professor','Sahabuddin Medical College And Hospital',replace('<p class="pbmit-firstletter">Here&rsquo;s a situation that comes up for many people: you move in later life. For most older adults, establishing a good working relationship with a new doctor is a challenge. If nothing else, it can take some time to feel that each party knows and understands the other. And they leave it to the new doctors to request health information from the previous doctors, which often arrives well after that first new patient visit. In this post, I&rsquo;ll share my list of the most useful health information</p>\n<p>A profile of a doctor is an effective personal marketing that doctors utilise to showcase their specialisation, qualifications and expertise. Creating a profile is beneficial for doctors as it ensures that others around them know their background</p>','\n',char(10)),'NB-1612',600,NULL,'1409961028','NULL','J00030',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-27 04:42:58');
INSERT INTO doctors VALUES(43,19,'Professor Dr. Samidur Rahman','professor-dr.-samidur-rahman','Pediatric Surgeon','MBBS, MS , Special in Hypospadias Surgery','Head of Pediatric Surgery Department','Dhaka Medical College & Hospital',replace('<p class="pbmit-firstletter">Professor Dr. Samidur Rahman is an established and highly skilled pediatric surgeon with over 22 years&rsquo; experience in the field of Pediatric Surgery. He is well regarded in pediatric surgical society, earning many recognitions and fame for his enthusiastic patient care and surgical qualities. Due to his keen and enthusiastic interest on Hypospadias surgery and consistent devoted work on this fine but difficult topic by this time he is well known Hypospadias surgeon in surgical society as well as all over the country. &nbsp;</p>\n<p>Dr. Samidur was born in Meherpur and graduated (MBBS) from Sylhet MAG Osmani Medical College on 1991. He stood 2nd in final professional examination under Chittagong university for which he was awarded &ldquo;Rear Admiral Mahbubur Rahman Memorial Gold Medal&rdquo;. He trained in pediatric surgery at Dhaka Shishu Hospital under Dhaka university and successfully completed MS (Pediatrics) degree in 2000.</p>\n<p>Dr. Samidur has been practicing as consultant Pediatric Surgeon since 2000 in different Medical Colleges in Bangladesh, of which last 12 years was in Sir Salimullah Medical College, Dhaka before joining in Dhaka Medical College and Hospital , the biggest academic hospital in the country. Now he is working as Professor of pediatric surgery and Head of unit IV in the Department of Pediatric Surgery, DMC&amp;H. He has keen interest in Hypospadias and Neonatal surgery and attended in many seminars and live workshops in home and abroad specially conducted by legendary hypospadias Surgeons Prof. Snod Grass( USA) and Prof. Hadidi(Germany).</p>\n<p>Dr. Samidur is a life member of Association of Pediatric Surgeons of Bangladesh(APSB) and Society of Surgeons of Bangladesh(SOSB).In addition, he obtained many certificates in different training programs, seminars, symposiums and workshops in the field of Pediatric Surgery including Pediatric laparospic Surgery. Now he is working as senior consultant pediatric surgeon, &nbsp;Director and chief &nbsp;surgeon at AMZ Hypospadias Center in AMZ &nbsp;hospital, Uttar Badda Dhaka.</p>','\n',char(10)),'NB-1511',1000,NULL,'1847331020','NULL','S00002',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-27 04:42:58');
