INSERT INTO doctors VALUES(45,20,'Assistant Professor Dr. Saleh Ahmad','asst.-prof.-dr.-md.-saleh-ahmed','Physical Medicine and Rehabilitation','MBBS, MD (Physical Medicine & Rehabilitation), MPH','Assistant Professor and Head of the Department Physical Medicine & Rehabilitation Department','Holy Family Red Crescent Medical College Trained in Rheumatology, Pain, Paralysis, Arthritis, Sports Injury and Rehabilitation Medicine',replace('<p class="pbmit-firstletter">Here&rsquo;s a situation that comes up for many people: you move in later life. For most older adults, establishing a good working relationship with a new doctor is a challenge. If nothing else, it can take some time to feel that each party knows and understands the other. And they leave it to the new doctors to request health information from the previous doctors, which often arrives well after that first new patient visit. In this post, I&rsquo;ll share my list of the most useful health information</p>\n<p>A profile of a doctor is an effective personal marketing that doctors utilise to showcase their specialisation, qualifications and expertise. Creating a profile is beneficial for doctors as it ensures that others around them know their background</p>','\n',char(10)),'NB-1510',1000,NULL,'1847331041','NULL','NULL',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-27 04:42:58');
INSERT INTO doctors VALUES(46,21,'Assistant Prof. Dr. Md. Monsur Rahman Chowdhury','asst.-dr.-md.-monsur-rahman-chowdhury','Plastic Surgery','MBBS , BCS, FCPS (Plastic Surgery)','Asst. Professor','National Institute of Burn and Plastic Surgery',replace('<p class="pbmit-firstletter">Here&rsquo;s a situation that comes up for many people: you move in later life. For most older adults, establishing a good working relationship with a new doctor is a challenge. If nothing else, it can take some time to feel that each party knows and understands the other. And they leave it to the new doctors to request health information from the previous doctors, which often arrives well after that first new patient visit. In this post, I&rsquo;ll share my list of the most useful health information</p>\n<p>A profile of a doctor is an effective personal marketing that doctors utilise to showcase their specialisation, qualifications and expertise. Creating a profile is beneficial for doctors as it ensures that others around them know their background</p>','\n',char(10)),'NB-1611',1500,NULL,'1726655168','NULL','M00076',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-27 04:42:58');
INSERT INTO doctors VALUES(47,21,'Professor Dr. Mohammad Nashir Uddin','asso.-prof.-dr.-mohammad-nashir-uddin','Burn, Plastic & Cosmetic Surgeon','MS (Plastic Surgery), FCPS (Surgery), FRCS (UK)','Professor & Director (Plastic Surgery)','National Institute of Burn and Plastic Surgery','<p class="pbmit-firstletter">Dr. Mohammad Nashir Uddin, Currently working as Professor &amp; Director (Plastic Surgery) in Burn and Plastic Surgery Department of National Institute of Burn and Plastic Surgery. In 1997, he joined government service through BCS 17th Batch. In his long surgical career of 25 years since 1999, he served with distinction as Assistant Registrar, Registrar, Resident Surgeon, Junior Consultant, Assistant Professor and Associate Professor at Dhaka Medical College Hospital, Mitford Hospital, Faridpur Medical College Hospital, Suhrawardy Hospital and National Heart Institute. He obtained FCPS in Surgery in 2003 and MS in Plastic Surgery in 2012. In 2019, he was awarded the FACS degree by the American College of Surgeons and later FRCS from Royal College of Physicians &amp; Surgeons, Glasgow, UK for his outstanding contributions to surgery. He also received advanced training in plastic surgery from Australia, Germany, Singapore, Turkey, Thailand and India. He attended and presented research papers in numerous scientific conferences at home and abroad. His numerous research articles have been published in various journals at home and abroad. Besides, he advises patients on various problems of burn and plastic surgery regularly on national television. Since the inception of AMZ Hospital, he has been serving patients in this institution as Chief Consultant in Burn, Plastic &amp; Cosmetic Surgery.</p>','OB-701',1500,NULL,'1726655168','NULL','N00001',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-27 04:42:58');
