INSERT INTO doctors VALUES(49,22,'Dr. Md. Tayabur Rahman','dr.-md.-tayabur-rahman','Psychiatrist','MBBS (DMC), BCS (Health), MD (Psychiatry, BSMMU)','Psychiatrist','National Institute of Mental Health, Sher-E-Banglanagar, Dhaka','<p class="MsoNoSpacing" style="text-align: justify;"><span style="font-family: ''Arial'',''sans-serif''; background: white;">Dr. Tayabur Rahman is a young Psychiatrist working as a Registrar at National Institute of Mental Health &amp; Hospital, Dhaka. After graduating from Dhaka Medical College, he got his MD in Psychiatry from BSMMU. He has unique experience as a UN peacekeeper in Haiti. Habitual speaker, cultural enthusiast Dr. Rahman has been involved in different academic and extracurricular activities throughout his career. He is a potential mental health educator on various online and offline platforms. Multitasker Dr. Rahman has keen interest in different Anxiety disorders, Psychosexual Health and Neuropsychiatry.</span></p>','NB-1607',800,NULL,'1847331013','NULL','T00018',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-27 04:42:58');
