INSERT INTO doctors VALUES(53,30,'Prof. Dr. A.K.M Musa Bhuiyan Bablu','prof.-dr.-a.k.m-musa-bhuiyan-bablu','Urology Specialist','MBBS, MS (Urology), BCS (Health)','Professor, Department of Urology','Mymensingh Medical College Hospital',replace('<p class="MsoNormal" style="margin-bottom: 18.75pt; text-align: justify; line-height: normal; background: white;"><span style="font-size: 12.0pt; font-family: ''Arial'',''sans-serif''; mso-fareast-font-family: ''Times New Roman''; color: #313131; mso-bidi-language: BN-BD;">Dr. A K M Musa Bhuiyan Bablu passed MBBS from Sylhet MAG Osmani Medical College in 1995 and joined government service in 2001 through 20th BCS. Later he obtained MS degree in Urology from Dhaka Medical College under Dhaka University. During his professional life, he received various advanced trainings in surgery and urology at home and abroad. Currently, he is working as an associate professor in Dhaka Medical College and Hospital.</span></p>\n<p class="MsoNormal" style="margin-bottom: 18.75pt; text-align: justify; line-height: normal; background: white;"><span style="font-size: 12.0pt; font-family: ''Arial'',''sans-serif''; mso-fareast-font-family: ''Times New Roman''; color: #313131; mso-bidi-language: BN-BD;">The services of urology and surgery are Dr. Masha Bhuiyan gives with great experience and care:</span></p>\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; margin-left: 0in; text-align: justify; text-indent: -.25in; line-height: normal; mso-list: l0 level1 lfo1; tab-stops: list .5in; background: white;"><!-- [if !supportLists]--><span style="font-size: 10.0pt; mso-bidi-font-size: 12.0pt; font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol; color: #313131; mso-bidi-language: BN-BD;"><span style="mso-list: Ignore;">&middot;<span style="font: 7.0pt ''Times New Roman'';">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span></span></span><!--[endif]--><span style="font-size: 12.0pt; font-family: ''Arial'',''sans-serif''; mso-fareast-font-family: ''Times New Roman''; color: #313131; mso-bidi-language: BN-BD;">You can consult modern treatments for kidney, ureter, urinary bladder, prostate, urinary tract, male reproductive system and sexual problems.</span></p>\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; margin-left: 0in; text-align: justify; text-indent: -.25in; line-height: normal; mso-list: l0 level1 lfo1; tab-stops: list .5in; background: white;"><!-- [if !supportLists]--><span style="font-size: 10.0pt; mso-bidi-font-size: 12.0pt; font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol; color: #313131; mso-bidi-language: BN-BD;"><span style="mso-list: Ignore;">&middot;<span style="font: 7.0pt ''Times New Roman'';">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span></span></span><!--[endif]--><span style="font-size: 12.0pt; font-family: ''Arial'',''sans-serif''; mso-fareast-font-family: ''Times New Roman''; color: #313131; mso-bidi-language: BN-BD;">Kidney and renal duct stones, urinary bladder tumors and stones, prostate enlargement, any problem of urinary tract are operated with the help of machines without cutting the abdomen.</span></p>\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; margin-left: 0in; text-align: justify; text-indent: -.25in; line-height: normal; mso-list: l0 level1 lfo1; tab-stops: list .5in; background: white;"><!-- [if !supportLists]--><span style="font-size: 10.0pt; mso-bidi-font-size: 12.0pt; font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol; color: #313131; mso-bidi-language: BN-BD;"><span style="mso-list: Ignore;">&middot;<span style="font: 7.0pt ''Times New Roman'';">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span></span></span><!--[endif]--><span style="font-size: 12.0pt; font-family: ''Arial'',''sans-serif''; mso-fareast-font-family: ''Times New Roman''; color: #313131; 