PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "permissions" ("id" integer primary key autoincrement not null, "name" varchar not null, "guard_name" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "roles" ("id" integer primary key autoincrement not null, "name" varchar not null, "guard_name" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "model_has_permissions" ("permission_id" integer not null, "model_type" varchar not null, "model_id" integer not null, foreign key("permission_id") references "permissions"("id") on delete cascade, primary key ("permission_id", "model_id", "model_type"));
CREATE TABLE IF NOT EXISTS "model_has_roles" ("role_id" integer not null, "model_type" varchar not null, "model_id" integer not null, foreign key("role_id") references "roles"("id") on delete cascade, primary key ("role_id", "model_id", "model_type"));
CREATE TABLE IF NOT EXISTS "role_has_permissions" ("permission_id" integer not null, "role_id" integer not null, foreign key("permission_id") references "permissions"("id") on delete cascade, foreign key("role_id") references "roles"("id") on delete cascade, primary key ("permission_id", "role_id"));
CREATE TABLE IF NOT EXISTS "activity_log" ("id" integer primary key autoincrement not null, "log_name" varchar, "description" text not null, "subject_type" varchar, "subject_id" integer, "causer_type" varchar, "causer_id" integer, "properties" text, "created_at" datetime, "updated_at" datetime, "event" varchar, "batch_uuid" varchar);
CREATE TABLE IF NOT EXISTS "departments" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "tagline" text, "shortDesc" text, "descriptions" text, "serial" integer, "is_active" tinyint(1) not null default '1', "text_icon" varchar, "bg-color" varchar, "text-color" varchar, "color" varchar, "custom_css" text, "meta_title" varchar, "meta_description" text, "canonical_url" varchar, "og_title" varchar, "og_description" text, "indexable" tinyint(1) not null default '1', "parent_id" integer, "created_by" integer not null, "updated_by" integer not null, "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("parent_id") references "departments"("id") on delete set null, foreign key("created_by") references "users"("id"), foreign key("updated_by") references "users"("id"));
CREATE TABLE IF NOT EXISTS "media" ("id" integer primary key autoincrement not null, "model_type" varchar not null, "model_id" integer not null, "uuid" varchar, "collection_name" varchar not null, "name" varchar not null, "file_name" varchar not null, "mime_type" varchar, "disk" varchar not null, "conversions_disk" varchar, "size" integer not null, "manipulations" text not null, "custom_properties" text not null, "generated_conversions" text not null, "responsive_images" text not null, "order_column" integer, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "doctors" ("id" integer primary key autoincrement not null, "department_id" integer not null, "name" varchar not null, "slug" varchar not null, "specialty" varchar not null, "qualifications" text not null, "designation" varchar not null, "institute" varchar not null, "biography" text, "chamber_location" varchar, "visit_fee" numeric, "report_fee" numeric, "phone" varchar, "email" varchar, "mis_code" varchar, "skills" text, "awards" text, "serial" integer not null default '0', "is_active" tinyint(1) not null default '1', "is_home_page" tinyint(1) not null default '0', "is_featured" tinyint(1) not null default '0', "meta_title" varchar, "meta_description" text, "canonical_url" varchar, "og_title" varchar, "og_description" text, "indexable" tinyint(1) not null default '1', "created_by" integer not null, "updated_by" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("department_id") references "departments"("id"), foreign key("created_by") references "users"("id"), foreign key("updated_by") references "users"("id"));
CREATE TABLE IF NOT EXISTS "doctor_timetables" ("id" integer primary key autoincrement not null, "doctor_id" integer not null, "day_of_week" integer not null, "start_time" time not null, "end_time" time not null, "slot_duration" integer not null default '30', "location" varchar, "is_active" tinyint(1) not null default '1', "max_patient" integer, "created_by" integer not null, "updated_by" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("doctor_id") references "doctors"("id") on delete cascade, foreign key("created_by") references "users"("id"), foreign key("updated_by") references "users"("id"));
CREATE TABLE IF NOT EXISTS "doctor_rests" ("id" integer primary key autoincrement not null, "doctor_id" integer not null, "start_date" date not null, "end_date" date, "reason" varchar, "type" varchar check ("type" in ('leave', 'emergency', 'holiday', 'Hajj', 'Umrah', 'Abroad', 'Others')) not null, "is_active" tinyint(1) not null default '1', "created_by" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("doctor_id") references "doctors"("id") on delete cascade, foreign key("created_by") references "users"("id"));
CREATE TABLE IF NOT EXISTS "center_of_excellences" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "icon" varchar, "created_by" integer, "updated_by" integer, "style" text, "meta_title" varchar, "meta_description" text, "canonical_url" varchar, "og_title" varchar, "og_description" text, "indexable" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("created_by") references "users"("id") on delete set null, foreign key("updated_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "hero_sliders" ("id" integer primary key autoincrement not null, "title" varchar not null, "subtitle" varchar, "description" text, "button_text" varchar, "button_url" varchar, "button_text_secondary" varchar, "button_url_secondary" varchar, "badge_text" varchar, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_by" integer not null, "updated_by" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("created_by") references "users"("id"), foreign key("updated_by") references "users"("id"));
CREATE TABLE IF NOT EXISTS "services" ("id" integer primary key autoincrement not null, "title" varchar not null, "slug" varchar not null, "icon" varchar, "short_description" varchar, "description" text, "price" numeric, "duration_minutes" integer, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "is_featured" tinyint(1) not null default '0', "meta_title" varchar, "meta_description" text, "indexable" tinyint(1) not null default '1', "created_by" integer not null, "updated_by" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("created_by") references "users"("id"), foreign key("updated_by") references "users"("id"));
CREATE TABLE IF NOT EXISTS "client_reviews" ("id" integer primary key autoincrement not null, "client_name" varchar not null, "client_designation" varchar, "client_company" varchar, "review_text" text not null, "rating" integer not null default '5', "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "is_featured" tinyint(1) not null default '0', "created_by" integer not null, "updated_by" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("created_by") references "users"("id"), foreign key("updated_by") references "users"("id"));
CREATE TABLE IF NOT EXISTS "patient_reviews" ("id" integer primary key autoincrement not null, "patient_name" varchar not null, "patient_phone" varchar, "doctor_id" integer, "department" varchar, "review_text" text not null, "rating" integer not null default '5', "status" varchar check ("status" in ('pending', 'approved', 'rejected')) not null default 'pending', "is_featured" tinyint(1) not null default '0', "admin_note" text, "created_by" integer, "updated_by" integer, "created_at" datetime, "updated_at" datetime, foreign key("doctor_id") references "doctors"("id") on delete set null, foreign key("created_by") references "users"("id") on delete set null, foreign key("updated_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "health_packages" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "badge" varchar, "short_description" varchar, "description" text, "includes" text, "original_price" numeric not null, "discounted_price" numeric, "duration_days" integer, "category" varchar check ("category" in ('general', 'cardiac', 'diabetes', 'cancer', 'maternity', 'pediatric', 'executive', 'other')) not null default 'general', "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "is_featured" tinyint(1) not null default '0', "meta_title" varchar, "meta_description" text, "indexable" tinyint(1) not null default '1', "created_by" integer not null, "updated_by" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("created_by") references "users"("id"), foreign key("updated_by") references "users"("id"));
CREATE TABLE IF NOT EXISTS "appointments" ("id" integer primary key autoincrement not null, "doctor_id" integer not null, "patient_name" varchar not null, "patient_email" varchar, "patient_phone" varchar not null, "appointment_date" date not null, "start_time" time not null, "end_time" time not null, "slot_duration" integer, "status" varchar check ("status" in ('pending', 'confirmed', 'cancelled', 'completed', 'no_show')) not null default 'pending', "notes" text, "cancellation_reason" text, "serial_number" integer, "serial_mode" varchar check ("serial_mode" in ('auto', 'manual')), "confirmed_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("doctor_id") references "doctors"("id") on delete cascade);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "permissions_name_guard_name_unique" on "permissions" ("name", "guard_name");
CREATE UNIQUE INDEX "roles_name_guard_name_unique" on "roles" ("name", "guard_name");
CREATE INDEX "model_has_permissions_model_id_model_type_index" on "model_has_permissions" ("model_id", "model_type");
CREATE INDEX "model_has_roles_model_id_model_type_index" on "model_has_roles" ("model_id", "model_type");
CREATE INDEX "subject" on "activity_log" ("subject_type", "subject_id");
CREATE INDEX "causer" on "activity_log" ("causer_type", "causer_id");
CREATE INDEX "activity_log_log_name_index" on "activity_log" ("log_name");
CREATE UNIQUE INDEX "departments_slug_unique" on "departments" ("slug");
CREATE INDEX "media_model_type_model_id_index" on "media" ("model_type", "model_id");
CREATE UNIQUE INDEX "media_uuid_unique" on "media" ("uuid");
CREATE INDEX "media_order_column_index" on "media" ("order_column");
CREATE UNIQUE INDEX "doctors_slug_unique" on "doctors" ("slug");
CREATE INDEX "doctor_timetables_doctor_id_day_of_week_index" on "doctor_timetables" ("doctor_id", "day_of_week");
CREATE INDEX "doctor_rests_doctor_id_start_date_end_date_index" on "doctor_rests" ("doctor_id", "start_date", "end_date");
CREATE UNIQUE INDEX "center_of_excellences_slug_unique" on "center_of_excellences" ("slug");
CREATE UNIQUE INDEX "services_slug_unique" on "services" ("slug");
CREATE UNIQUE INDEX "health_packages_slug_unique" on "health_packages" ("slug");
CREATE INDEX "appointments_doctor_date_start_idx" on "appointments" ("doctor_id", "appointment_date", "start_time");
CREATE INDEX "appointments_doctor_date_status_idx" on "appointments" ("doctor_id", "appointment_date", "status");
CREATE INDEX "appointments_appointment_date_index" on "appointments" ("appointment_date");
CREATE UNIQUE INDEX "appointments_doctor_date_serial_unique" on "appointments" ("doctor_id", "appointment_date", "serial_number");
CREATE UNIQUE INDEX "appointments_doctor_date_time_unique" on "appointments" ("doctor_id", "appointment_date", "start_time", "end_time");
COMMIT;
